import sys

path = '/Users/yzj/GolandProjects/alertmesh/web/src/pages/k8s/K8sPods.tsx'
with open(path, 'r') as f:
    lines = f.readlines()

# 找到 PodTerminalDrawer 注释行
start_idx = None
for i, line in enumerate(lines):
    if 'PodTerminalDrawer' in line and line.strip().startswith('//'):
        start_idx = i
        break

if start_idx is None:
    print('ERROR: PodTerminalDrawer not found')
    sys.exit(1)

print(f'Replacing from line {start_idx+1} (total {len(lines)} lines)')

kept = lines[:start_idx]

new_code = """\n// ─── PodTerminalDrawer —— xterm.js ───────────────────────────────────────────\n\ntype FileOp = 'upload' | 'download'\n\nfunction PodTerminalDrawer({\n  dsId, open, onClose, target\n}: {\n  dsId: string\n  open: boolean\n  onClose: () => void\n  target: { ns: string; name: string; container: string } | null\n}) {\n  const termContainerRef = useRef<HTMLDivElement>(null)\n  const xtermRef = useRef<import('@xterm/xterm').Terminal | null>(null)\n  const fitAddonRef = useRef<import('@xterm/addon-fit').FitAddon | null>(null)\n  const wsRef = useRef<WebSocket | null>(null)\n  const [connected, setConnected] = useState(false)\n  const [fileModalOpen, setFileModalOpen] = useState(false)\n  const [fileOp, setFileOp] = useState<FileOp>('upload')\n  const [downloadPath, setDownloadPath] = useState('')\n  const [uploadDestPath, setUploadDestPath] = useState('/tmp')\n  const [uploading, setUploading] = useState(false)\n\n  useEffect(() => {\n    if (!open || !target || !termContainerRef.current) return\n\n    let term: import('@xterm/xterm').Terminal\n    let fitAddon: import('@xterm/addon-fit').FitAddon\n    let ws: WebSocket\n    let destroyed = false\n    let ro: ResizeObserver\n\n    Promise.all([\n      import('@xterm/xterm'),\n      import('@xterm/addon-fit'),\n    ]).then(([{ Terminal }, { FitAddon }]) => {\n      if (destroyed || !termContainerRef.current) return\n\n      term = new Terminal({\n        cursorBlink: true,\n        fontSize: 14,\n        fontFamily: \"Menlo, Monaco, Consolas, 'Courier New', monospace\",\n        theme: {\n          background: '#1e1e1e',\n          foreground: '#d4d4d4',\n          cursor: '#f8f8f2',\n          selectionBackground: '#264f78',\n        },\n        allowProposedApi: true,\n        scrollback: 5000,\n        convertEol: false,\n      })\n      xtermRef.current = term\n\n      fitAddon = new FitAddon()\n      fitAddonRef.current = fitAddon\n      term.loadAddon(fitAddon)\n      term.open(termContainerRef.current)\n      setTimeout(() => { try { fitAddon.fit() } catch (err) { /* ignore */ } }, 50)\n\n      const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws'\n      const wsUrl = `${protocol}://${window.location.host}/api/k8s/pod/terminal?ds=${dsId}&namespace=${target.ns}&name=${target.name}&container=${target.container}`\n      ws = new WebSocket(wsUrl)\n      wsRef.current = ws\n      ws.binaryType = 'arraybuffer'\n\n      ws.onopen = () => {\n        if (destroyed) return\n        setConnected(true)\n        doSendResize(ws, term.cols, term.rows)\n        setTimeout(() => {\n          if (ws.readyState === WebSocket.OPEN) {\n            ws.send(new Uint8Array([0, 13]).buffer)\n          }\n        }, 200)\n      }\n\n      ws.onmessage = (evt) => {\n        if (destroyed) return\n        const buf = new Uint8Array(evt.data as ArrayBuffer)\n        if (buf.length < 1) return\n        const ch = buf[0]\n        if (ch === 1 || ch === 2) {\n          term.write(buf.slice(1))\n        }\n      }\n\n      ws.onclose = () => {\n        if (destroyed) return\n        setConnected(false)\n        term.write('\\r\\n\\x1b[33m[连接已关闭]\\x1b[0m\\r\\n')\n      }\n\n      ws.onerror = () => {\n        if (destroyed) return\n        term.write('\\r\\n\\x1b[31m[连接失败]\\x1b[0m\\r\\n')\n      }\n\n      term.onData((data) => {\n        if (ws.readyState === WebSocket.OPEN) {\n          const encoded = new TextEncoder().encode(data)\n          const msg = new Uint8Array([0, ...encoded])\n          ws.send(msg.buffer)\n        }\n      })\n\n      term.onResize(({ cols, rows }) => {\n        if (ws.readyState === WebSocket.OPEN) {\n          doSendResize(ws, cols, rows)\n        }\n      })\n\n      ro = new ResizeObserver(() => {\n        try { fitAddon.fit() } catch (err) { /* ignore */ }\n      })\n      if (termContainerRef.current) ro.observe(termContainerRef.current)\n    })\n\n    return () => {\n      destroyed = true\n      try { ro?.disconnect() } catch (err) { /* ignore */ }\n      ws?.close()\n      term?.dispose()\n      xtermRef.current = null\n      fitAddonRef.current = null\n      wsRef.current = null\n      setConnected(false)\n    }\n  }, [open, target?.ns, target?.name, target?.container, dsId])\n\n  function doSendResize(ws: WebSocket, cols: number, rows: number) {\n    if (ws.readyState !== WebSocket.OPEN) return\n    const payload = JSON.stringify({ Width: cols, Height: rows })\n    const encoded = new TextEncoder().encode(payload)\n    const msg = new Uint8Array([4, ...encoded])\n    ws.send(msg.buffer)\n  }\n\n  const handleDownload = async () => {\n    if (!downloadPath || !target) return\n    const url = `/api/k8s/pod/download?ds=${dsId}&namespace=${target.ns}&name=${target.name}&container=${target.container}&path=${encodeURIComponent(downloadPath)}`\n    const a = document.createElement('a')\n    a.href = url\n    a.download = downloadPath.split('/').pop() || 'file'\n    document.body.appendChild(a)\n    a.click()\n    document.body.removeChild(a)\n    setFileModalOpen(false)\n  }\n\n  const handleUpload = async (file: File) => {\n    if (!target) return false\n    setUploading(true)\n    const formData = new FormData()\n    formData.append('file', file)\n    try {\n      const resp = await fetch(\n        `/api/k8s/pod/upload?ds=${dsId}&namespace=${target.ns}&name=${target.name}&container=${target.container}&path=${encodeURIComponent(uploadDestPath)}`,\n        { method: 'POST', body: formData }\n      )\n      const json = await resp.json()\n      if (json.code === 0) {\n        message.success('文件上传成功')\n        setFileModalOpen(false)\n      } else {\n        message.error(json.message || '上传失败')\n      }\n    } catch (e: any) {\n      message.error(e.message || '上传失败')\n    } finally {\n      setUploading(false)\n    }\n    return false\n  }\n\n  return (\n    <>\n      <Drawer\n        title={\n          <Space>\n            <span style={{ fontWeight: 600 }}>{target?.name ?? ''}</span>\n            <Tag color=\"blue\">{target?.container ?? ''}</Tag>\n            <Tag color={connected ? 'success' : 'default'}>{connected ? '已连接' : '未连接'}</Tag>\n          </Space>\n        }\n        placement=\"right\"\n        width=\"65%\"\n        open={open}\n        onClose={onClose}\n        destroyOnClose\n        extra={\n          <Space>\n            <Button size=\"small\" icon={<UploadOutlined />}\n              onClick={() => { setFileOp('upload'); setFileModalOpen(true) }}\n            >上传/下载</Button>\n            <Button size=\"small\" icon={<ReloadOutlined />}\n              onClick={() => { wsRef.current?.close() }}\n            >重连</Button>\n          </Space>\n        }\n        styles={{\n          body: { padding: 0, background: '#1e1e1e', display: 'flex', flexDirection: 'column', overflow: 'hidden' },\n          header: { background: '#252526', borderBottom: '1px solid #3c3c3c' },\n        }}\n      >\n        <div ref={termContainerRef} style={{ flex: 1, minHeight: 0, width: '100%' }} />\n      </Drawer>\n\n      <Modal\n        title=\"文件上传 / 下载\"\n        open={fileModalOpen}\n        onCancel={() => setFileModalOpen(false)}\n        footer={null}\n        width={480}\n        zIndex={1100}\n      >\n        <div style={{ marginBottom: 16 }}>\n          <Radio.Group value={fileOp} onChange={e => setFileOp(e.target.value)}>\n            <Radio.Button value=\"upload\"><UploadOutlined /> 上传文件</Radio.Button>\n            <Radio.Button value=\"download\"><DownloadOutlined /> 下载文件</Radio.Button>\n          </Radio.Group>\n        </div>\n\n        {fileOp === 'upload' && (\n          <Space direction=\"vertical\" style={{ width: '100%' }}>\n            <div>\n              <span style={{ marginRight: 8 }}>目标路径：</span>\n              <Input value={uploadDestPath} onChange={e => setUploadDestPath(e.target.value)}\n                placeholder=\"如 /tmp\" style={{ width: 280 }} />\n            </div>\n            <Upload beforeUpload={handleUpload} showUploadList={false} disabled={uploading}>\n              <Button icon={<UploadOutlined />} loading={uploading}>选择并上传文件</Button>\n            </Upload>\n            <span style={{ color: '#888', fontSize: 12 }}>文件将上传到容器的指定目录</span>\n          </Space>\n        )}\n\n        {fileOp === 'download' && (\n          <Space direction=\"vertical\" style={{ width: '100%' }}>\n            <div>\n              <span style={{ marginRight: 8 }}>容器内文件路径：</span>\n              <Input value={downloadPath} onChange={e => setDownloadPath(e.target.value)}\n                placeholder=\"如 /tmp/app.log\" style={{ width: 280 }} />\n            </div>\n            <Button icon={<DownloadOutlined />} onClick={handleDownload} disabled={!downloadPath}>\n              下载文件\n            </Button>\n          </Space>\n        )}\n      </Modal>\n    </>\n  )\n}\n"""

with open(path, 'w') as f:
    f.writelines(kept)
    f.write(new_code)

with open(path, 'r') as f:
    result = f.readlines()
print(f'Done. Total lines: {len(result)}')
